import psycopg2
from psycopg2 import sql
import getpass
import sys

class PostgreSQLAdmin:
    def __init__(self, host, port, database, user, password):
        self.connection_params = {
            'host': host,
            'port': port,
            'database': database,
            'user': user,
            'password': password
        }
        self.connection = None
    
    def connect(self):
        try:
            self.connection = psycopg2.connect(**self.connection_params)
            return True
        except Exception as e:
            print(f"Connection failed: {e}")
            return False
    
    def disconnect(self):
        if self.connection:
            self.connection.close()
    
    def install_extension(self, extension_name):
        if not self.connection:
            print("Not connected to database")
            return False
        
        try:
            with self.connection.cursor() as cursor:
                # Sanitize extension name to prevent injection
                sanitized_extension = sql.Identifier(extension_name).as_string(cursor)
                query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(sql.Identifier(extension_name))
                cursor.execute(query)
                self.connection.commit()
                print(f"Extension '{extension_name}' installed successfully")
                return True
        except Exception as e:
            print(f"Failed to install extension '{extension_name}': {e}")
            self.connection.rollback()
            return False
    
    def list_extensions(self):
        if not self.connection:
            print("Not connected to database")
            return []
        
        try:
            with self.connection.cursor() as cursor:
                cursor.execute("SELECT extname FROM pg_extension;")
                extensions = [row[0] for row in cursor.fetchall()]
                return extensions
        except Exception as e:
            print(f"Failed to list extensions: {e}")
            return []

def main():
    print("PostgreSQL Admin Tool")
    print("-" * 20)
    
    # Get connection parameters securely
    host = input("Host (default: localhost): ").strip() or "localhost"
    port = input("Port (default: 5432): ").strip() or "5432"
    database = input("Database: ").strip()
    user = input("Username: ").strip()
    password = getpass.getpass("Password: ")
    
    # Initialize admin tool
    admin = PostgreSQLAdmin(host, port, database, user, password)
    
    if not admin.connect():
        print("Failed to connect to database")
        sys.exit(1)
    
    print("\nConnected to database successfully")
    print("Available extensions:", admin.list_extensions())
    
    while True:
        print("\nOptions:")
        print("1. Install extension")
        print("2. List extensions")
        print("3. Exit")
        
        choice = input("Enter choice (1-3): ").strip()
        
        if choice == "1":
            extension_name = input("Enter extension name to install: ").strip()
            if extension_name:
                admin.install_extension(extension_name)
            else:
                print("Extension name cannot be empty")
        
        elif choice == "2":
            extensions = admin.list_extensions()
            print("Installed extensions:")
            for ext in extensions:
                print(f"  - {ext}")
        
        elif choice == "3":
            break
        
        else:
            print("Invalid choice")
    
